from pathlib import Path, PureWindowsPath
import hashlib
import json

output_dir = Path("Z:/FOXAI/System/EngineeringWorkshop/missions/ENG-20260721-215227-E95BEF_V1A3C1D_R2_WEB_PORTABLE_DIAGNOSTIC")
required = {
    "V1A3C1_FAILURE_DIAGNOSTIC.json",
    "V1A3C1_FAILURE_TRACEBACK.txt",
    "V1A3C1_DIAGNOSTIC_RECEIPT.json",
}
present = {path.name for path in output_dir.iterdir() if path.is_file()}
assert present == required, (present, required)

diagnostic = json.loads(
    (output_dir / "V1A3C1_FAILURE_DIAGNOSTIC.json").read_text(
        encoding="utf-8"
    )
)
receipt = json.loads(
    (output_dir / "V1A3C1_DIAGNOSTIC_RECEIPT.json").read_text(
        encoding="utf-8"
    )
)
traceback_text = (
    output_dir / "V1A3C1_FAILURE_TRACEBACK.txt"
).read_text(encoding="utf-8")

def normalize_windows_path(value):
    text = str(value or "").strip().strip('"')
    return str(PureWindowsPath(text)).casefold()

assert diagnostic["mission_id"] == "ENG-20260721-215227-E95BEF"
assert diagnostic["subject_mission_id"] == "ENG-20260721-172935-37F095"
assert diagnostic["result"] in {"captured_failure", "unexpected_success"}
assert diagnostic["protected_direct_context_count"] == 1

context = diagnostic["context"]
assert normalize_windows_path(context["launcher_path"]) == normalize_windows_path(
    "Z:/FOXAI/START_FOXAI_WEB_PORTABLE.bat"
)
assert normalize_windows_path(context["script_path"]) == normalize_windows_path(
    "Z:/FOXAI/core/foxai_web.py"
)
assert normalize_windows_path(
    context["resolved_interpreter_path"]
) == normalize_windows_path("Z:/FOXAI/env/python/python.exe")

exception = diagnostic.get("exception") or {}
if diagnostic["result"] == "captured_failure":
    assert exception.get("exception_type") == "ValueError", exception
    assert str(exception.get("message", "")).strip(), exception
    assert diagnostic["last_successful_stage"] == (
        "preliminary_closure_construction"
    )
    assert "ValueError" in traceback_text
else:
    assert diagnostic["result"] == "unexpected_success"

assert receipt["diagnostic_command_returned_success_after_recording"] is True
assert receipt["normal_closure_outputs_generated"] is False
assert receipt["interpreter_child_processes"] == 0
assert receipt["shell_child_processes"] == 0
assert receipt["network_used"] is False
assert receipt["packages_installed"] is False
assert receipt["models_loaded"] is False

parse_counters = diagnostic.get("parse_counters") or {}
assert int(parse_counters.get("maximum_reads_per_source_file") or 0) <= 1
assert int(parse_counters.get("peak_source_bytes") or 0) <= 8388608

for item in receipt.get("diagnostic_outputs_before_receipt", []):
    path = output_dir / item["name"]
    assert path.is_file()
    assert path.stat().st_size == item["size_bytes"]
    assert hashlib.sha256(path.read_bytes()).hexdigest() == item["sha256"]

total_output_bytes = sum(
    path.stat().st_size
    for path in output_dir.iterdir()
    if path.is_file()
)
assert total_output_bytes < 1048576

exception_summary = {
    "status": "AGENT_FOX_V1A3C1D_R2_DIAGNOSTIC_RETAINED",
    "mission_id": diagnostic["mission_id"],
    "subject_mission_id": diagnostic["subject_mission_id"],
    "result": diagnostic["result"],
    "exception_type": exception.get("exception_type"),
    "exception_message": exception.get("message"),
    "last_successful_stage": diagnostic.get("last_successful_stage"),
    "active_source_path": exception.get("current_source_path"),
    "active_import_record": exception.get("current_import_record"),
    "reached_node_count": (
        diagnostic.get("closure_counters") or {}
    ).get("reached_node_count"),
    "edge_count": (
        diagnostic.get("closure_counters") or {}
    ).get("edge_count"),
    "unresolved_count": (
        diagnostic.get("closure_counters") or {}
    ).get("unresolved_count"),
    "source_read_count": parse_counters.get("source_read_count"),
    "maximum_reads_per_source_file": parse_counters.get(
        "maximum_reads_per_source_file"
    ),
    "peak_source_bytes": parse_counters.get("peak_source_bytes"),
    "elapsed_seconds": diagnostic.get("elapsed_seconds"),
    "diagnostic_output_paths": [
        str(output_dir / name)
        for name in sorted(required)
    ],
    "total_output_bytes": total_output_bytes,
}
print(json.dumps(exception_summary, sort_keys=True))

